script.code:
let entry = {{workflowparams:allData}};

if(entry.purchase_order_no_type !== -9999 && (
  !entry.purchase_order_no || entry.purchase_order_no === null || entry.purchase_order_no === ''
)) {
  entry.purchase_order_no = 'draft'
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_plant: {{node:code_draft_check_doc_no.data.entry.po_plant}},
    purchase_order_no: {{node:code_draft_check_doc_no.data.entry.purchase_order_no}},
    table_po: {{node:code_draft_check_doc_no.data.entry.table_po}}
  })
}

let entry = {{workflowparams:allData}};

if (
  entry.purchase_order_no_type !== -9999 &&
  (!entry.purchase_order_no ||
    entry.purchase_order_no === null ||
    entry.purchase_order_no === "" ||
    entry.previous_status == "Draft")
) {
  entry.purchase_order_no = 'issued'
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "po_supplier_id", label: "Supplier Name" },
  { name: "po_plant", label: "Plant" },
  { name: "purchase_order_no", label: "PO Number" },
  {
    name: "table_po",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    po_supplier_id: {{node:code_check_doc_no.data.entry.po_supplier_id}},
    po_plant: {{node:code_check_doc_no.data.entry.po_plant}},
    purchase_order_no: {{node:code_check_doc_no.data.entry.purchase_order_no}},
    table_po: {{node:code_check_doc_no.data.entry.table_po}}
  })
}

return {
  lineItem: JSON.stringify({{node:code_check_doc_no.data.entry.table_po}}),
  itemFields: 'item_name,item_id,item_desc',
  quantityFields: 'quantity'
}

let table = {{node:code_check_doc_no.data.entry}};

table.table_po = table.table_po.filter(item => (item.item_name || item.item_desc || item.item_id) && item.quantity > 0)

return { table };

return {
  length: {{node:code_filter_lines.data.table.table_po}}.length
}

const draftGRCount = {{node:search_draft_gr.data.total}};
const draftPICount = {{node:search_draft_pi.data.total}};
let message = [];
let status = 'Passed';

if(draftGRCount > 0) {
  const grRows = {{node:search_draft_gr.data.data}} || [];
  const draftGRNo = (Array.isArray(grRows) ? grRows : [grRows]).map(r => r.gr_no).filter(Boolean).join(', ');
  if(draftGRNo) message.push(draftGRNo);
}

if(draftPICount > 0) {
  const piRows = {{node:search_draft_pi.data.data}} || [];
  const draftPINo = (Array.isArray(piRows) ? piRows : [piRows]).map(r => r.purchase_invoice_no).filter(Boolean).join(', ');
  if(draftPINo) message.push(draftPINo);
}

if(message.length > 0) {
  status = 'Failed'
}

return {
  status: status,
  message: status === 'Passed' ? '' : 'The purchase order has existing GR/PI records in draft status. Proceeding will delete these record: ' + message.join(', ')
}

const its = {{node:get_its_pre.data.data}};
const r = Array.isArray(its) ? its[0] : its;
const issued = ({{workflowparams:allData.po_status}}) === "Issued";
const isInternal = !!(issued && r && r.id && Number(r.auto_create_so) === 1);
return {
  isInternal: isInternal,
  sellerOrg: r && r.seller_org_id ? r.seller_org_id : "",
  sellerCustomer: r && r.seller_customer_id ? r.seller_customer_id : ""
};

const lines = {{workflowparams:allData.table_po}};
const aliasesRaw = {{node:search_alias_pre.data.data}};
const customerRaw = {{node:get_customer_pre.data.data}};
const currencyRaw = {{node:get_currency_pre.data.data}};
const poCurrency = {{workflowparams:allData.po_currency}};
const autoSkip = {{workflowparams:allData.auto_so_skip}} === true;
const autoConfirmed = {{workflowparams:allData.auto_so_confirmed}} === true;
const toArr = (x) => Array.isArray(x) ? x : (x ? [x] : []);
const one = (x) => Array.isArray(x) ? x[0] : x;
const aliasArr = toArr(aliasesRaw);
const aliasMap = {};
aliasArr.forEach((a) => { aliasMap[a.buyer_item_id + "|" + a.buyer_uom_id] = a; });
const stock = (lines || []).filter((l) => l.item_id && parseFloat(l.quantity) > 0);
const missing = [];
stock.forEach((l) => { if (!aliasMap[l.item_id + "|" + l.quantity_uom]) missing.push(l.item_name || l.item_id); });
const cur = one(currencyRaw);
const curCode = cur ? (cur.currency_code || "") : "";
const currencyMismatch = !!(poCurrency && curCode && poCurrency !== curCode);
const customer = one(customerRaw);
const custName = customer && customer.customer_com_name ? customer.customer_com_name : "the seller organization";

const blocked = missing.length > 0 || currencyMismatch;
// 406: not eligible (missing alias / currency) and not yet skipped
const block406 = blocked && !autoSkip;
// 408: eligible, but the user hasn't decided whether to auto-create the SO
const confirm408 = !blocked && !autoConfirmed && !autoSkip;

let msg406 = "";
if (missing.length > 0) {
  msg406 = "The following items are not linked in Item Alias for the seller organization: " + missing.join(", ");
} else if (currencyMismatch) {
  msg406 = "PO currency (" + poCurrency + ") does not match the seller organization currency (" + curCode + ").";
}
const msg408 = "This purchase order qualifies for internal trading. A linked Sales Order will be created for " + custName + ".";

return { block406: block406, confirm408: confirm408, msg406: msg406, msg408: msg408 };

let updatedLineItem = [];
let entry = {{workflowparams:allData.po_status}} == 'Draft' ? {{node:code_draft_check_doc_no.data.entry}} : {{node:code_filter_lines.data.table}};

for(const [index, poLineItem] of entry.table_po.entries()) {
  const receivedQty = poLineItem.received_qty === null || poLineItem.received_qty === undefined || poLineItem.received_qty === '' ? 0 : parseFloat(poLineItem.received_qty);
  const formattedItem = {
    ...poLineItem,
    quantity: parseFloat(poLineItem.quantity || 0).toFixed(3),
    unit_price: parseFloat(poLineItem.unit_price || 0).toFixed(4),
    gross: parseFloat(poLineItem.gross || 0).toFixed(4),
    discount: parseFloat(poLineItem.discount || 0).toFixed(4),
    discount_amount: parseFloat(poLineItem.discount_amount || 0).toFixed(4),
    tax_amount: parseFloat(poLineItem.tax_amount || 0).toFixed(4),
    po_amount: parseFloat(poLineItem.po_amount || 0).toFixed(4),
    min_price: parseFloat(poLineItem.min_price || 0).toFixed(4),
    max_price: parseFloat(poLineItem.max_price || 0).toFixed(4),
    received_qty: receivedQty,
    outstanding_quantity: (parseFloat(poLineItem.quantity || 0) - receivedQty).toFixed(3),
    supplier_id: entry.po_supplier_id || "",
    plant_id: entry.po_plant || "",
    payment_term_id: entry.po_payment_terms || "",
    shipping_preference_id: entry.po_shipping_preference || "",
    billing_state_id: entry.billing_address_state || "",
    billing_country_id: entry.billing_address_country || "",
    shipping_state_id: entry.shipping_address_state || "",
    shipping_country_id: entry.shipping_address_country || "",
    item_category_id: poLineItem.item_category_id || "",
    line_index: index + 1,
    organization_id: entry.organization_id,
    line_status: !poLineItem.line_status || poLineItem.line_status === '' || poLineItem.line_status === 'Draft' ? entry.po_status : poLineItem.line_status,
    po_created_by: {{global:nickname}}
  };

  updatedLineItem.push(formattedItem);
}

entry.partially_received = !entry.partially_received || entry.partially_received === '' ? `0 / ${updatedLineItem.length}` : entry.partially_received;
entry.fully_received = !entry.fully_received || entry.fully_received === '' ? `0 / ${updatedLineItem.length}` : entry.fully_received;
entry.po_total_gross = parseFloat(entry.po_total_gross || 0).toFixed(4);
entry.po_total_discount = parseFloat(entry.po_total_discount || 0).toFixed(4);
entry.po_total_tax = parseFloat(entry.po_total_tax || 0).toFixed(4);
entry.po_total = parseFloat(entry.po_total || 0).toFixed(4);
entry.myr_total_amount = parseFloat(entry.myr_total_amount || 0).toFixed(4);

entry.table_po = updatedLineItem;

return { entry };

const lineItem = {{node:code_fillback.data.entry.table_po}};

const uniqueItemIDs = [
  ...new Set(lineItem.filter((item) => item.item_id).map((item) => item.item_id))
];

return {
  itemIDs: uniqueItemIDs
}

const tablePO = {{node:get_po_full.data.data.table_po}} || [];

return {
  itemIDs: tablePO.map(item => item.item_id).filter(Boolean)
}

const poFull      = {{node:get_po_full.data.data}};
const latestLines = (poFull && poFull.table_po) || [];
const existing    = {{node:search_onorder.data.data}} || [];
const items       = {{node:search_items.data.data}} || [];
const pageStatus  = {{workflowparams:allData.page_status}};

const round3 = (n) => Math.round((parseFloat(n) || 0) * 1000) / 1000;

const baseQtyFor = (line) => {
  const itemData = items.find(d => String(d.id) === String(line.item_id));
  const altQty = parseFloat(line.quantity) || 0;
  let baseQty = altQty;
  if (itemData && Array.isArray(itemData.table_uom_conversion) && itemData.table_uom_conversion.length > 0) {
    const conv = itemData.table_uom_conversion.find(c => String(c.alt_uom_id) === String(line.quantity_uom));
    if (conv) baseQty = round3(altQty * parseFloat(conv.base_qty));
  }
  return baseQty;
};

const desired = [];
for (const [index, line] of latestLines.entries()) {
  const itemData = items.find(d => String(d.id) === String(line.item_id));
  if (!itemData) continue;
  desired.push({
    po_line_id: line.id,
    purchase_order_number: poFull.purchase_order_no,
    material_id: line.item_id,
    purchase_order_line: index + 1,
    scheduled_qty: baseQtyFor(line),
    plant_id: poFull.po_plant,
    organization_id: poFull.organization_id,
    po_id: poFull.id,
    parent_id: line.preq_id || null,
    parent_line_id: line.preq_line_id || null
  });
}

const toAdd = [], toUpdate = [], toDelete = [];
const usedExistingIds = new Set();

const findExisting = (d) => {
  let m = existing.find(e => e.po_line_id != null && String(e.po_line_id) === String(d.po_line_id) && !usedExistingIds.has(e.id));
  if (m) return m;
  return existing.find(e => !usedExistingIds.has(e.id) && String(e.material_id) === String(d.material_id) && Number(e.purchase_order_line) === Number(d.purchase_order_line));
};

const isNew = (pageStatus === 'Add' || pageStatus === 'Clone');

for (const d of desired) {
  const match = isNew ? null : findExisting(d);
  if (!match) {
    toAdd.push({
      purchase_order_number: d.purchase_order_number,
      material_id: d.material_id,
      purchase_order_line: d.purchase_order_line,
      scheduled_qty: d.scheduled_qty,
      open_qty: d.scheduled_qty,
      received_qty: 0,
      plant_id: d.plant_id,
      organization_id: d.organization_id,
      po_id: d.po_id,
      po_line_id: d.po_line_id,
      parent_id: d.parent_id,
      parent_line_id: d.parent_line_id
    });
  } else {
    usedExistingIds.add(match.id);
    const received = Math.max(0, round3(match.received_qty || 0));
    const newOpen = Math.max(0, round3(d.scheduled_qty - received));
    toUpdate.push({
      id: match.id,
      scheduled_qty: d.scheduled_qty,
      open_qty: newOpen,
      purchase_order_line: d.purchase_order_line,
      po_line_id: d.po_line_id
    });
  }
}

if (!isNew) {
  for (const e of existing) {
    if (!usedExistingIds.has(e.id)) toDelete.push({ id: e.id });
  }
}

return { toAdd, toUpdate, toDelete };

const poID = {{node:get_po_full.data.data.id}};
const poLineItem = {{node:get_po_full.data.data.table_po}} || [];
const preqData = {{node:search_preq.data.data}};
const onOrderData = {{node:search_onorder.data.data}} || [];
let latestPREQData = [];

if(preqData && preqData.length > 0) {
  for(const preq of preqData) {
    let processedItems = preq.table_pr.map(item => {
      const poItem = poLineItem.find(po => String(po.preq_line_id) === String(item.id));
      const newItem = { ...item };
      let orderQty = 0;

      if(poItem) {
        const onOrderItem = onOrderData.length > 0 ? onOrderData.find(onOrder => String(onOrder.parent_line_id) === String(item.id)) : null;
        if(onOrderItem) {
          orderQty = parseFloat(item.order_qty || 0) - parseFloat(onOrderItem.scheduled_qty || 0) + parseFloat(poItem.quantity || 0);
        } else {
          orderQty = parseFloat(item.order_qty || 0) + parseFloat(poItem.quantity || 0);
        }
        newItem.order_qty = parseFloat(orderQty).toFixed(3);
        newItem.po_id = [...(item.po_id || []), poID];
        newItem.po_line_id = [...(item.po_line_id || []), poItem.id];
      }

      return newItem;
    });

    let preqStatus = preq.preq_status;
    if(preq.preq_type === 'Contract' && preq.preq_status !== 'Force Completed') {
      const isCompleted = processedItems.every(item =>
        parseFloat(item.pr_line_qty) === parseFloat(item.order_qty || 0)
      );
      preqStatus = isCompleted ? 'Completed' : 'Processing';
    } else if(preq.preq_status !== 'Force Completed') {
      preqStatus = 'Completed';
    }

    processedItems = processedItems.map((it) => {
      return { ...it, line_status: preqStatus };
    });

    latestPREQData.push({
      id: preq.id,
      preq_status: preqStatus,
      table_pr: processedItems,
    });
  }
}

return { latestPREQData };

const its = {{node:get_its.data.data}};
const r = Array.isArray(its) ? its[0] : its;
const isInternal = !!(r && r.id && Number(r.auto_create_so) === 1);
return {
  isInternal: isInternal,
  sellerOrg: r && r.seller_org_id ? r.seller_org_id : "",
  sellerCustomer: r && r.seller_customer_id ? r.seller_customer_id : "",
  pricingSource: r && r.pricing_source ? r.pricing_source : "po_price",
  paymentTermSource: r && r.payment_term_source ? r.payment_term_source : "seller_customer"
};

const rows = {{node:search_addr.data.data}};
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);
const countryIds = [...new Set(arr.map(a => a.address_country_id).filter(Boolean))];
const stateIds = [...new Set(arr.map(a => a.adddress_state).filter(Boolean))];
return {
  countryIds: countryIds.length ? countryIds : ["0"],
  stateIds: stateIds.length ? stateIds : ["0"]
};

const aliasesRaw = {{node:search_alias.data.data}};
const arr = Array.isArray(aliasesRaw) ? aliasesRaw : (aliasesRaw ? [aliasesRaw] : []);
const ids = [...new Set(arr.map((a) => a.seller_item_id).filter(Boolean))];
return { sellerItemIds: ids.length ? ids : ["0"] };

const po = {{node:get_po_full.data.data}};
const aliasesRaw = {{node:search_alias.data.data}};
const customerRaw = {{node:get_customer.data.data}};
const accRaw = {{node:get_acc.data.data}};
const currencyRaw = {{node:get_currency.data.data}};
const ruleRaw = {{node:get_so_rule.data.data}};
const sellerItemsRaw = {{node:search_seller_items.data.data}};
const existingRaw = {{node:search_existing_link.data.data}};
const addrRaw = {{node:search_addr.data.data}};
const shipPurposeRaw = {{node:get_ship_purpose.data.data}};
const countriesRaw = {{node:search_country.data.data}};
const statesRaw = {{node:search_state.data.data}};
const sellerOrg = {{node:code_its.data.sellerOrg}};
const sellerCustomer = {{node:code_its.data.sellerCustomer}};
const pricingSource = {{node:code_its.data.pricingSource}};
const paymentTermSource = {{node:code_its.data.paymentTermSource}};
const autoSkip = {{workflowparams:allData.auto_so_skip}} === true;
const autoConfirmed = {{workflowparams:allData.auto_so_confirmed}} === true;

const toArr = (x) => Array.isArray(x) ? x : (x ? [x] : []);
const one = (x) => Array.isArray(x) ? x[0] : x;

const aliasArr = toArr(aliasesRaw);
const customer = one(customerRaw);
const acc = one(accRaw);
const currency = one(currencyRaw);
const rule = one(ruleRaw);
const sellerItems = toArr(sellerItemsRaw);
const existingArr = toArr(existingRaw);
const itemMap = {};
sellerItems.forEach((it) => { itemMap[it.id] = it; });
const addrArr = toArr(addrRaw);
const shipPurpose = one(shipPurposeRaw);
const countries = toArr(countriesRaw);
const states = toArr(statesRaw);

const alreadyLinked = existingArr.length > 0;

// alias map keyed by buyer item + buyer uom
const aliasMap = {};
aliasArr.forEach((a) => { aliasMap[a.buyer_item_id + "|" + a.buyer_uom_id] = a; });

// --- setup-driven resolvers (current value implemented; default == current) ---
// Pricing source: how the SO unit price is derived from the PO line.
const computePrice = (l, rate) => {
  switch (pricingSource) {
    case "po_price":
    default:
      // Preserve the line total across the UOM conversion.
      return Math.round((parseFloat(l.unit_price) || 0) / rate * 10000) / 10000;
  }
};
// NOTE: tax is intentionally NOT carried from the PO — PO and SO tax setups are
// independent (different tax_code/rate), so the SO is created tax-free.
// Payment-term source: where the SO header payment term comes from.
const computePaymentTerm = () => {
  switch (paymentTermSource) {
    case "seller_customer":
    default:
      return customer ? (customer.customer_payment_term_id || null) : null;
  }
};

// Packing / weight helpers (mirror SOchangeItem.buildPackingWeightData), driven
// off the seller Item record + the seller UOM. unrestricted_qty is intentionally
// NOT set (not required for an auto-created SO).
const getPackingDetail = (tpd, uom) =>
  (Array.isArray(tpd) && uom) ? (tpd.find((c) => c.uom_id === uom) || null) : null;
const getBaseQty = (tuc, uom) => {
  if (!Array.isArray(tuc) || !uom) return 1;
  const c = tuc.find((x) => x.alt_uom_id === uom);
  return c && c.base_qty ? c.base_qty : 1;
};

const lines = (po.table_po || []).filter((l) => l.item_id && parseFloat(l.quantity) > 0);
const missing = [];
const soLines = [];
lines.forEach((l, i) => {
  const a = aliasMap[l.item_id + "|" + l.quantity_uom];
  if (!a) { missing.push(l.item_name || l.item_id); return; }
  const rate = parseFloat(a.conversion_rate) || 1;
  const soQty = Math.round((parseFloat(l.quantity) || 0) * rate * 1000) / 1000;
  const sit = itemMap[a.seller_item_id] || null;
  const pd = sit ? getPackingDetail(sit.table_packing_detail, a.seller_uom_id) : null;
  const packingConversion = pd && pd.quantity ? pd.quantity : 1;
  const packingUOM = pd ? (pd.packing_uom_id || "") : "";
  const baseQty = sit ? getBaseQty(sit.table_uom_conversion, a.seller_uom_id) : 1;
  const weightConversion = Math.round((Number(sit ? sit.net_weight : 0) || 0) * baseQty * 1000) / 1000;
  const packingQty = packingConversion ? Math.round((soQty / packingConversion) * 1000) / 1000 : 0;
  const netWeight = Math.round(soQty * weightConversion * 1000) / 1000;
  soLines.push({
    item_name: a.seller_item_id,
    item_id: sit ? (sit.material_name || "") : "",
    so_desc: sit && sit.material_desc ? sit.material_desc : (l.item_desc || ""),
    item_category_id: sit ? (sit.item_category || "") : "",
    custom_fields: sit ? (sit.custom_fields || null) : null,
    so_quantity: soQty,
    so_item_uom: a.seller_uom_id,
    so_item_price: computePrice(l, rate),
    so_gross: parseFloat(l.gross) || 0,
    so_discount: parseFloat(l.discount) || 0,
    so_discount_amount: parseFloat(l.discount_amount) || 0,
    so_tax_preference: "",
    so_tax_percentage: 0,
    so_tax_amount: 0,
    so_tax_inclusive: 0,
    so_amount: Math.round(((parseFloat(l.gross) || 0) - (parseFloat(l.discount_amount) || 0)) * 10000) / 10000,
    packing_uom: packingUOM,
    packing_conversion: packingConversion,
    packing_qty: packingQty,
    weight_conversion: weightConversion,
    net_weight: netWeight,
    line_index: i + 1
  });
});

// currency gate
const curCode = currency ? (currency.currency_code || "") : "";
const exRate = (curCode && curCode !== "----" && curCode !== "MYR")
  ? (currency.currency_buying_rate || 1) : 1;
const currencyMismatch = !!(po.po_currency && curCode && po.po_currency !== curCode);

// addresses
const cMap = {}; countries.forEach((c) => { cMap[c.id] = c.country_name; });
const sMap = {}; states.forEach((s) => { sMap[s.id] = s.state_name; });
const shipPurposeId = shipPurpose ? shipPurpose.id : null;
const fmt = (a, stateName, countryName, typeUpper) => {
  const ln = [a.address_line_1, a.address_line_2, a.address_line_3, a.address_line_4].filter((x) => x);
  const addressLines = ln.join((ln[ln.length - 1] || "").endsWith(",") ? " " : ", ");
  const cp = [a.address_city, a.address_postal_code, a.adddress_state ? stateName : "", a.address_country_id ? countryName : ""].filter((x) => x);
  const cityDetails = cp.join((cp[cp.length - 1] || "").endsWith(",") ? " " : ", ");
  const att = a.address_attention ? "\nAttention: " + a.address_attention : "";
  const person = [a.address_name, a.address_phone].filter((x) => x).join(" | ");
  return [person, "\n" + typeUpper + " Address", addressLines, cityDetails, att].filter(Boolean).join("\n");
};
const addr = {};
addrArr.forEach((a) => {
  const isShip = a.address_purpose_id === shipPurposeId;
  const t = isShip ? "shipping" : "billing";
  addr[t + "_address_line_1"] = a.address_line_1;
  addr[t + "_address_line_2"] = a.address_line_2;
  addr[t + "_address_line_3"] = a.address_line_3;
  addr[t + "_address_line_4"] = a.address_line_4;
  addr[t + "_address_city"] = a.address_city;
  addr[t + "_address_state"] = a.adddress_state;
  addr[t + "_postal_code"] = a.address_postal_code;
  addr[t + "_address_country"] = a.address_country_id;
  addr[t + "_address_name"] = a.address_name;
  addr[t + "_address_phone"] = a.address_phone;
  addr[t + "_attention"] = a.address_attention;
  addr[t + "_address_code"] = a.address_code;
  const formatted = fmt(a, sMap[a.adddress_state] || "", cMap[a.address_country_id] || "", isShip ? "Shipping" : "Billing");
  if (isShip) addr.cust_shipping_address = formatted; else addr.cust_billing_address = formatted;
});

const doCreate = !alreadyLinked && missing.length === 0 && !currencyMismatch && autoConfirmed;
const needConfirm = !alreadyLinked && (missing.length > 0 || currencyMismatch);

let msg = "";
if (missing.length > 0) {
  msg = "The following items are not linked in Item Alias for the seller organization: " + missing.join(", ");
} else if (currencyMismatch) {
  msg = "PO currency (" + po.po_currency + ") does not match the seller organization currency (" + curCode + ").";
}

const payload = {
  page_status: "Add",
  so_status: "Issued",
  previous_status: "",
  so_no: "",
  so_no_type: rule ? rule.id : -9999,
  so_date: po.po_date,
