  source_po_id: po.id,
  cust_po: po.purchase_order_no,
  cust_po_date: po.po_date,
  ...addr
};

return { doCreate: doCreate, needConfirm: needConfirm, autoSkip: autoSkip, msg: msg, payload: payload };

const r = {{node:wf_create_so.data}};
const sd = r && r.data ? r.data : null;
const ok = !!(sd && sd.so_id);
const err = !r ? "" : (r.message || r.msg || (r.data && (r.data.message || r.data.msg)) || "");
return {
  ok: ok,
  soId: ok ? sd.so_id : null,
  soNo: ok ? sd.so_no : null,
  errMsg: ok ? "" : (err || "The linked Sales Order could not be created.")
};

const poData = {{node:code_get_latest.data.poData}};

return {
